:root {
    --er-red: #b91c1c;
    --er-red-dark: #7f1d1d;
    --er-red-soft: #fef2f2;
    --er-blue: #1d4ed8;
    --er-green: #047857;
    --er-yellow: #b45309;
    --er-bg: #f8fafc;
    --er-card: #ffffff;
    --er-text: #0f172a;
    --er-muted: #64748b;
    --er-border: #e2e8f0;
    --er-shadow: 0 16px 40px rgba(15, 23, 42, 0.08);
}

html {
    -webkit-text-size-adjust: 100%;
    text-size-adjust: 100%;
}

body {
    background: radial-gradient(circle at top left, rgba(185, 28, 28, 0.08), transparent 26rem), radial-gradient(circle at bottom right, rgba(29, 78, 216, 0.06), transparent 30rem), var(--er-bg);
    color: var(--er-text);
    font-family: Inter, Arial, sans-serif;
}

a {
    color: var(--er-red);
    text-decoration: none;
}

a:hover {
    color: var(--er-red-dark);
}

.er-page {
    max-width: 1500px;
    margin: 0 auto;
    padding: 24px;
}

.er-page-header {
    background: linear-gradient(135deg, #ffffff 0%, #fef2f2 100%);
    border: 1px solid var(--er-border);
    border-radius: 24px;
    padding: 24px;
    box-shadow: var(--er-shadow);
    margin-bottom: 22px;
}

.er-page-title {
    margin: 0;
    color: var(--er-text);
    font-size: 28px;
    line-height: 1.15;
    font-weight: 900;
    letter-spacing: -0.03em;
}

.er-page-subtitle {
